object.Code:
var vars = context.session.variables; 

// Read SourceId for the target flow 
var sSourceId = vars.RTDS_OP_SourceId; 
if (sSourceId === undefined || sSourceId === null) { 
    sSourceId = ''; 
} 

// Read optional specific OperationId to land on (empty = use IsFirstOperation) 
var sOperationId = vars.RTDS_OP_OperationId; 
if (sOperationId === undefined || sOperationId === null) { 
    sOperationId = ''; 
} 

// Store in component-internal session vars (__ prefix = hidden from CSV, internal to component) 
vars.__fj_sourceId     = sSourceId; 
vars.__fj_operationId  = sOperationId; 
vars.__fj_error        = '0'; 

log_debug('[RTDS] flowJump: SourceId=' + sSourceId + ' OperationId=' + sOperationId);

var vars = context.session.variables; 

var sSourceId = vars.__fj_sourceId; 

if (sSourceId === undefined || sSourceId === null || sSourceId.length === 0) { 
    log_error('[RTDS] flowJump: SourceId is empty - cannot fetch'); 
    vars.RTDS_error    = 'RTDS_FLOWJUMP_NO_SOURCE_ID'; 
    vars.__fj_error    = '1'; 
    return; 
} 

// Build the API URL from the base stored in session 
var sApiBase = vars.RTDS_apiBase; 
if (sApiBase === undefined || sApiBase === null) { 
    sApiBase = ''; 
} 
var sUrl = sApiBase + '/api/routing-table/' + sSourceId; 

log_debug('[RTDS] flowJump: fetching ' + sUrl); 

return httpRequest(sUrl, { method: 'GET' }).then(function(response) { 
    if (response.statusCode !== 200) { 
        log_error('[RTDS] flowJump: API returned ' + response.statusCode); 
        vars.RTDS_error = 'RTDS_FLOWJUMP_API_ERROR_' + response.statusCode; 
        vars.__fj_error = '1'; 
        return; 
    } 
    vars.__fj_responseBody = response.body; 
    log_debug('[RTDS] flowJump: fetch OK for ' + sSourceId); 
});

var vars = context.session.variables; 

// Abort early if a previous node flagged an error 
if (vars.__fj_error === '1') { 
    log_warn('[RTDS] flowJump: skipping parse due to earlier error'); 
    return; 
} 

// Parse the response body 
var json; 
try { 
    json = JSON.parse(vars.__fj_responseBody); 
} catch (e) { 
    log_error('[RTDS] flowJump: JSON parse failed: ' + e.message); 
    vars.RTDS_error = 'RTDS_FLOWJUMP_PARSE_ERROR'; 
    vars.__fj_error = '1'; 
    return; 
} 

if (!json || !json.Operations || json.Operations.length === 0) { 
    log_error('[RTDS] flowJump: Operations array missing or empty'); 
    vars.RTDS_error = 'RTDS_FLOWJUMP_PARSE_ERROR'; 
    vars.__fj_error = '1'; 
    return; 
} 

// Write flow header fields to session 
vars.RTDS_sourceId            = json.SourceId; 
vars.RTDS_name                = json.Name; 
vars.RTDS_project             = json.Project; 
vars.RTDS_promptLibrary       = json.PromptLibrary; 
vars.RTDS_supportedLanguages  = json.SupportedLanguages; 

// Build operation index keyed by Id 
var opIndex = {}; 
var ops = json.Operations; 
for (var i = 0; i < ops.length; i++) { 
    if (ops[i].Id) { 
        opIndex[ops[i].Id] = ops[i]; 
    } 
} 
vars.RTDS_opIndex = opIndex; 

// Determine the step to resume at 
var sOperationId = vars.__fj_operationId; 

if (sOperationId !== undefined && sOperationId !== null && sOperationId.length > 0) { 
    // Explicit target operation supplied 
    vars.RTDS_nextStepId = sOperationId; 
    log_debug('[RTDS] flowJump: resuming at operationId=' + sOperationId); 
} else { 
    // Find the lexicographically lowest IsFirstOperation 
    var sFirstId = null; 
    for (var j = 0; j < ops.length; j++) { 
        if (ops[j].IsFirstOperation === true) { 
            if (sFirstId === null || ops[j].Id < sFirstId) { 
                sFirstId = ops[j].Id; 
            } 
        } 
    } 
    if (sFirstId === null) { 
        log_error('[RTDS] flowJump: no IsFirstOperation found in new flow'); 
        vars.RTDS_error = 'RTDS_NO_ENTRY_POINT'; 
        vars.__fj_error = '1'; 
        return; 
    } 
    vars.RTDS_nextStepId = sFirstId; 
    log_debug('[RTDS] flowJump: entry point is ' + sFirstId); 
}
